refsection.programlisting:
load(GROCERDIR+'\data\us_modinf.dat')
bounds('1960q3','2008q2')
// make a dynamic model averaging estimation with '100*lagts(-1,delts(log(GDPDEFL)))' as endogenous
// variable, 'const', '100*delts(log(GDPDEFL))' and '100*lagts(delts(log(GDPDEFL)))' as imposed exogenous variables
// 'UNRATE', '100*delts(log(PCECC96))', '100*delts(log(PRFI))', 100*delts(log(GDPC96))' and 'log(HOUST) as free
// exogenous variables, forgetting factor for past observations in the calculation of the time-varying coefficients set to 0.99,
// forgetting factor of past performance set to 0.99 and default values for other parameters
resdma=DMA('100*lagts(-1,delts(log(GDPDEFL)))',['const';'100*delts(log(GDPDEFL))';'100*lagts(delts(log(GDPDEFL)))'],...
['UNRATE';'100*delts(log(PCECC96))';'100*delts(log(PRFI))';'100*delts(log(GDPC96))';'log(HOUST)'],0.99,0.99)

// plot the number of expected variables
pltdma_expnbvar(resdma)
// plot the probabilities and expected coefficients
// of all variables
pltdma_probvar(resdma,'all')
// display the best model at some dates
prtdma_bestmodel(resdma,['1988q2';'1993q2';'1998q2';'2003q2';'2008q2'],%io(2))

// makes a dynamic model averaging estimation with the same variables, but with forgetting factors now set to 0.95
// and big volume information saved into files gdpdefl1.dat, gdpdefl2.dat,... in folder 'c:/mydma'
resdma=DMA('100*lagts(-1,delts(log(GDPDEFL)))',['const';'100*delts(log(GDPDEFL))';'100*lagts(delts(log(GDPDEFL)))'],...
['UNRATE';'100*delts(log(PCECC96))';'100*delts(log(PRFI))';'100*delts(log(GDPC96))';'log(HOUST)'],0.95,0.95,'prefix_db=c:/mydma/gdpdefl')
